INSERT INTO examples (name, category, framework, files, dependencies, metadata) VALUES ('"content-center"', '"layout"', '"vanilla"', '{"demo.css": ".content-center {\n  display: grid;\n  place-content: center;\n  gap: 1ch;\n}", "demo.html": "<article class=\"content-center\">\n  <h1>Content Center</h1>\n</article>"}', '{}', '{"original_path": "patterns/layout/content-center"}'), ('"deconstructed-pancake"', '"layout"', '"vanilla"', '{"demo.css": ".parent {\n  display: flex;\n  flex-wrap: wrap;\n  justify-content: center;\n}\n\n.box {\n  /*  Stretching: */\n  flex: 1 1 150px; \n  margin: 5px;\n  background: red;\n  gap: 1rem;\n}", "demo.html": "<div class=\"parent\">\n  <div class=\"box\">1</div>\n  <div class=\"box\">2</div>\n  <div class=\"box\">3</div>\n</div>"}', '{}', '{"original_path": "patterns/layout/deconstructed-pancake"}'), ('"fluffy-center"', '"layout"', '"vanilla"', '{"demo.css": ".fluffy-center {\n  padding: 15vmin;\n  /* any large amount of padding works */\n}", "demo.html": "<article>\n  <h1 class=\"fluffy-center\">Fluffy Center</h1>\n</article>"}', '{}', '{"original_path": "patterns/layout/fluffy-center"}'), ('"gentle-flex"', '"layout"', '"vanilla"', '{"demo.css": ".gentle-flex {\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  justify-content: center;\n  gap: 1ch;\n}", "demo.html": "<article class=\"gentle-flex\">\n  <h1>Gentle Flex</h1>\n</article>"}', '{}', '{"original_path": "patterns/layout/gentle-flex"}'), ('"holy-grail"', '"layout"', '"vanilla"', '{"demo.css": ".parent {\n  display: grid;\n  grid-template: auto 1fr auto / auto 1fr auto;\n}\n\nheader {\n  padding: 2rem;\n  grid-column: 1 / 4;\n}\n\n.left-side {\n  grid-column: 1 / 2;\n}\n\nmain {\n  grid-column: 2 / 3;\n}\n\n.right-side {\n  grid-column: 3 / 4;\n}\n\nfooter {\n  grid-column: 1 / 4;\n}", "demo.html": "<div class=\"parent\">\n    <header class=\"section coral\">Header</header>\n    <div class=\"left-side section blue\">Left Sidebar</div>\n    <main class=\"section green\"> Main Content</main>\n    <div class=\"right-side section yellow\">Right Sidebar</div>\n    <footer class=\"section coral\">Footer</footer>\n  </div>"}', '{}', '{"original_path": "patterns/layout/holy-grail"}'), ('"line-up"', '"layout"', '"vanilla"', '{"demo.css": ".container {\n  display: grid;\n  grid-gap: 1rem;\n  grid-template-columns: repeat(3, 1fr);\n}\n\n.visual {\n  height: 100px;\n  width: 100%;\n}\n\n.card {\n  display: flex;\n  flex-direction: column;\n  padding: 1rem;\n  justify-content: space-between;\n}\n\nh3 {\n  margin: 0\n}", "demo.html": "<div class=\"container\">\n  <div class=\"card\">\n    <h3>Title - Card 1</h3>\n    <p contenteditable>Medium length description with a few more words here.</p>\n    <div class=\"visual\"></div>\n  </div>\n  <div class=\"card\">\n    <h3>Title - Card 2</h3>\n    <p contenteditable>Long Description. Lorem ipsum dolor sit, amet consectetur adipisicing elit.</p>\n    <div class=\"visual\"></div>\n  </div>\n  <div class=\"card\">\n    <h3>Title - Card 3</h3>\n    <p contenteditable>Short Description.</p>\n    <div class=\"visual\"></div>\n  </div>\n</div>"}', '{}', '{"original_path": "patterns/layout/line-up"}'), ('"pancake-stack"', '"layout"', '"vanilla"', '{"demo.css": ".parent {\n  display: grid;\n  grid-template-rows: auto 1fr auto;\n\n  /* Just for parent demo size */\n  height: 100vh;\n}", "demo.html": "<div class=\"parent\">\n  <header class=\"section yellow\">Header</header>\n  <main class=\"section blue\">Main</main>\n  <footer class=\"section green\">Footer Content</footer>\n</div>"}', '{}', '{"original_path": "patterns/layout/pancake-stack"}'), ('"pop-n-plop"', '"layout"', '"vanilla"', '{"demo.css": "article {\n  position: relative;\n}\n\n.pop-n-plop {\n  position: absolute;\n  top: 50%;\n  left: 50%;\n  transform: translate(-50%, -50%);\n}", "demo.html": "<article>\n  <h1 class=\"pop-n-plop\">Pop n'' Plop</h1>\n</article>"}', '{}', '{"original_path": "patterns/layout/pop-n-plop"}'), ('"repeat-auto-minmax"', '"layout"', '"vanilla"', '{"demo.css": ".parent {\n  display: grid;\n  grid-gap: 1rem;\n  grid-template-columns: repeat(auto-fit, minmax(150px, 1fr));\n}", "demo.html": "<div class=\"parent white\">\n    <div class=\"box\">1</div>\n    <div class=\"box\">2</div>\n    <div class=\"box\">3</div>\n    <div class=\"box\">4</div>\n  </div>\n  "}', '{}', '{"original_path": "patterns/layout/repeat-auto-minmax"}'), ('"sidebar-says"', '"layout"', '"vanilla"', '{"demo.css": ".parent {\n  display: grid;\n  grid-template-columns: minmax(100px, 25%) 1fr;\n}", "demo.html": "<div class=\"parent\">\n    <div class=\"section yellow\" contenteditable>\n    Min: 100px / Max: 25%\n    </div>\n    <div class=\"section blue\" contenteditable>\n      This element takes the second grid position (1fr), meaning\n      it takes up the rest of the remaining space.\n    </div>\n  </div>"}', '{}', '{"original_path": "patterns/layout/sidebar-says"}'), ('"super-centered"', '"layout"', '"vanilla"', '{"demo.css": ".parent {\n  display: grid;\n  place-items: center;\n\n  /* Just for parent demo size */\n  height: 100vh;\n}", "demo.html": "<div class=\"parent\">\n  <div class=\"box\" contenteditable=\"\">\n    :)\n  </div>\n</div>"}', '{}', '{"original_path": "patterns/layout/super-centered"}'), ('"twelve-span-grid"', '"layout"', '"vanilla"', '{"demo.css": ".parent {\n  display: grid;\n  grid-template-columns: repeat(12, 1fr);\n}\n\n.span-12 {\n  grid-column: 1 / span 12;\n}\n\n.span-6 {\n  grid-column: 1 / span 6;\n}\n\n.span-4 {\n  grid-column: 4 / span 4;\n}\n\n.span-2 {\n  grid-column: 3 / span 2;\n}\n\n/* centering text */\n.section {\n  display: grid;\n  place-items: center;\n  text-align: center\n}", "demo.html": " <div class=\"parent\">\n  <div class=\"span-12 section coral\">Span 12</div>\n  <div class=\"span-6 section green\">Span 6</div>\n  <div class=\"span-4 section yellow\">Span 4</div>\n  <div class=\"span-2 section blue\">Span 2</div>\n</div>\n"}', '{}', '{"original_path": "patterns/layout/twelve-span-grid"}'), ('"audio-effects"', '"media"', '"vanilla"', '{"demo.css": ":root {\n  color-scheme: dark light;\n}\n\nhtml {\n  box-sizing: border-box;\n}\n\n*,\n*:before,\n*:after {\n  box-sizing: inherit;\n}\n\nbody {\n  margin: 1rem;\n  font-family: system-ui, sans-serif;\n}\n", "demo.html": "<!DOCTYPE html>\n<html lang=\"en\">\n  <head>\n    <meta charset=\"utf-8\" />\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />\n    <link\n      rel=\"icon\"\n      href=\"data:image/svg+xml,<svg xmlns=%22http://www.w3.org/2000/svg%22 viewBox=%220 0 100 100%22><text y=%22.9em%22 font-size=%2290%22>\ud83d\udd09</text></svg>\"\n    />\n    <title>How to add effects to audio</title>\n  </head>\n  <body>\n    <h1>How to add effects to audio</h1>\n    <button type=\"button\">Press to hear audio effect</button>\n  </body>\n</html>\n", "demo.js": "const button = document.querySelector(''button'');\n\nbutton.addEventListener(''click'', () => {\n  const audioCtx = new (window.AudioContext || window.webkitAudioContext)();\n  const oscillator = audioCtx.createOscillator();\n  oscillator.type = ''sine'';\n  // Value is in hertz.\n  oscillator.frequency.setValueAtTime(420, audioCtx.currentTime);\n\n  const biquadFilter = audioCtx.createBiquadFilter();\n  biquadFilter.type = ''lowpass'';\n  biquadFilter.frequency.setValueAtTime(200, audioCtx.currentTime + 1);\n  oscillator.connect(biquadFilter);\n\n  biquadFilter.connect(audioCtx.destination);\n  oscillator.start();\n  oscillator.stop(2);\n});\n"}', '{}', '{"original_path": "patterns/media/audio-effects"}'), ('"media-session"', '"media"', '"vanilla"', '{"demo.css": ":root {\n  color-scheme: dark light;\n}\nhtml {\n  box-sizing: border-box;\n}\n*,\n*:before,\n*:after {\n  box-sizing: inherit;\n}\nbody {\n  margin: 1rem;\n  font-family: system-ui, sans-serif;\n}\nvideo {\n  display: block;\n  margin-top: 10px;\n  max-width: 100%;\n}\n", "demo.html": "<!DOCTYPE html>\n<html lang=\"en\">\n  <head>\n    <meta charset=\"utf-8\" />\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />\n    <link\n      rel=\"icon\"\n      href=\"data:image/svg+xml,<svg xmlns=%22http://www.w3.org/2000/svg%22 viewBox=%220 0 100 100%22><text y=%22.9em%22 font-size=%2290%22>\ud83d\udcfa</text></svg>\"\n    />\n    <title>How to customize media notifications</title>\n  </head>\n  <body>\n    <h1>How to customize media notifications</h1>\n    <video controls playsinline src=\"https://storage.googleapis.com/media-session/caminandes/short.mp4\"></video>\n    <p>Credits: Media files are \u00a9 copyright Blender Foundation | <a href=\"https://www.blender.org\">www.blender.org</a>.</p>\n  </body>\n</html>\n", "demo.js": "const video = document.querySelector(\"video\");\n\nnavigator.mediaSession.metadata = new MediaMetadata({\n  title: \"Caminandes 2: Gran Dillama - Blender Animated Short\",\n  artist: \"Blender Foundation\",\n  artwork: [\n    { src: \"https://storage.googleapis.com/media-session/caminandes/artwork-96.png\",  sizes: \"96x96\" },\n    { src: \"https://storage.googleapis.com/media-session/caminandes/artwork-128.png\", sizes: \"128x128\" },\n    { src: \"https://storage.googleapis.com/media-session/caminandes/artwork-256.png\", sizes: \"256x256\" },\n    { src: \"https://storage.googleapis.com/media-session/caminandes/artwork-512.png\", sizes: \"512x512\" },\n  ],\n});\n\nnavigator.mediaSession.setActionHandler(\"play\", async () => {\n  // Resume playback\n  try {\n    await video.play();\n  } catch (err) {\n    console.error(err.name, err.message);\n  }\n});\n\nnavigator.mediaSession.setActionHandler(\"pause\", () => {\n  // Pause active playback\n  video.pause();\n});\n\nvideo.addEventListener(\"play\", () => {\n  navigator.mediaSession.playbackState = \"playing\";\n});\n\nvideo.addEventListener(\"pause\", () => {\n  navigator.mediaSession.playbackState = \"paused\";\n});\n"}', '{}', '{"original_path": "patterns/media/media-session"}'), ('"microphone-process"', '"media"', '"vanilla"', '{"demo (2).js": "const startMicrophoneButton = document.querySelector(''#startMicrophoneButton'');\nconst stopMicrophoneButton = document.querySelector(''#stopMicrophoneButton'');\n\nlet stream;\n\nstartMicrophoneButton.addEventListener(\"click\", async () => {\n  // Prompt the user to use their microphone.\n  stream = await navigator.mediaDevices.getUserMedia({\n    audio: true,\n  });\n  const context = new AudioContext();\n  const source = context.createMediaStreamSource(stream);\n\n  // Load and execute the module script.\n  await context.audioWorklet.addModule(\"processor.js\");\n  // Create an AudioWorkletNode. The name of the processor is the\n  // one passed to registerProcessor() in the module script.\n  const processor = new AudioWorkletNode(context, \"processor\");\n\n  source.connect(processor).connect(context.destination);\n\n  stopMicrophoneButton.disabled = false;\n  log(\"Your microphone audio is being used.\");\n});\n\nstopMicrophoneButton.addEventListener(\"click\", () => {\n  // Stop the stream.\n  stream.getTracks().forEach(track => track.stop());\n\n  log(\"Your microphone audio is not used anymore.\");\n});\n", "demo.css": ":root {\n  color-scheme: dark light;\n}\nhtml {\n  box-sizing: border-box;\n}\n*,\n*:before,\n*:after {\n  box-sizing: inherit;\n}\nbody {\n  margin: 1rem;\n  font-family: system-ui, sans-serif;\n}\nbutton {\n  display: block;\n  margin-bottom: 4px;\n}\npre {\n  color: red;\n  white-space: pre-line;\n}\n", "demo.html": "<!DOCTYPE html>\n<html lang=\"en\">\n  <head>\n    <meta charset=\"utf-8\" />\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />\n    <link\n      rel=\"icon\"\n      href=\"data:image/svg+xml,<svg xmlns=%22http://www.w3.org/2000/svg%22 viewBox=%220 0 100 100%22><text y=%22.9em%22 font-size=%2290%22>\ud83c\udf99\ufe0f</text></svg>\"\n    />\n    <title>How to process audio from the user''s microphone</title>\n  </head>\n  <body>\n    <h1>How to process audio from the user''s microphone</h1>\n    <button id=\"startMicrophoneButton\">Start using microphone</button>\n    <button id=\"stopMicrophoneButton\" disabled>Stop using microphone</button>\n    <pre id=\"logs\"></pre>\n  </body>\n</html>\n", "demo.js": "// This file is evaluated in the audio rendering thread\n// upon context.audioWorklet.addModule() call.\n\nclass WorkletProcessor extends AudioWorkletProcessor {\n  process([input], [output]) {\n    // Copy inputs to outputs.\n    output[0].set(input[0]);\n    return true;\n  }\n}\n  \nregisterProcessor(\"processor\", WorkletProcessor);\n"}', '{}', '{"original_path": "patterns/media/microphone-process"}'), ('"microphone-record"', '"media"', '"vanilla"', '{"demo.css": ":root {\n  color-scheme: dark light;\n}\nhtml {\n  box-sizing: border-box;\n}\n*,\n*:before,\n*:after {\n  box-sizing: inherit;\n}\nbody {\n  margin: 1rem;\n  font-family: system-ui, sans-serif;\n}\nbutton {\n  display: block;\n  margin-bottom: 4px;\n}\npre {\n  color: red;\n  white-space: pre-line;\n}\n", "demo.html": "<!DOCTYPE html>\n<html lang=\"en\">\n  <head>\n    <meta charset=\"utf-8\" />\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />\n    <link\n      rel=\"icon\"\n      href=\"data:image/svg+xml,<svg xmlns=%22http://www.w3.org/2000/svg%22 viewBox=%220 0 100 100%22><text y=%22.9em%22 font-size=%2290%22>\ud83c\udf99\ufe0f</text></svg>\"\n    />\n    <title>How to record audio from the user''s microphone</title>\n  </head>\n  <body>\n    <h1>How to record audio from the user''s microphone</h1>\n    <button id=\"startMicrophoneButton\">Start using microphone</button>\n    <button id=\"stopMicrophoneButton\" disabled>Stop using microphone</button>\n    <button id=\"startRecordButton\" disabled>Start recording</button>\n    <button id=\"stopRecordButton\" disabled>Stop recording</button>\n    <pre id=\"logs\"></pre>\n  </body>\n</html>\n", "demo.js": "const startMicrophoneButton = document.querySelector(''#startMicrophoneButton'');\nconst stopMicrophoneButton = document.querySelector(''#stopMicrophoneButton'');\nconst startRecordButton = document.querySelector(''#startRecordButton'');\nconst stopRecordButton = document.querySelector(''#stopRecordButton'');\n\nlet stream;\nlet recorder;\n\nstartMicrophoneButton.addEventListener(\"click\", async () => {\n  // Prompt the user to use their microphone.\n  stream = await navigator.mediaDevices.getUserMedia({ audio: true });\n  recorder = new MediaRecorder(stream);\n\n  stopMicrophoneButton.disabled = false;\n  startRecordButton.disabled = false;\n  log(\"Your microphone audio is being used.\");\n});\n\nstopMicrophoneButton.addEventListener(\"click\", () => {\n  // Stop the stream.\n  stream.getTracks().forEach(track => track.stop());\n\n  startRecordButton.disabled = true;\n  stopRecordButton.disabled = true;\n  log(\"Your microphone audio is not used anymore.\");\n});\n\nstartRecordButton.addEventListener(\"click\", async () => {\n  // For the sake of more legible code, this sample only uses the\n  // `showSaveFilePicker()` method. In production, you need to\n  // cater for browsers that don''t support this method, as\n  // outlined in https://web.dev/patterns/files/save-a-file/.\n\n  // Prompt the user to choose where to save the recording file.\n  const suggestedName = \"microphone-recording.webm\";\n  const handle = await window.showSaveFilePicker({ suggestedName });\n  const writable = await handle.createWritable();\n\n  // Start recording.\n  recorder.start();\n  recorder.addEventListener(\"dataavailable\", async (event) => {\n    // Write chunks to the file.\n    await writable.write(event.data);\n    if (recorder.state === \"inactive\") {\n      // Close the file when the recording stops.\n      await writable.close();\n    }\n  });\n\n  stopRecordButton.disabled = false;\n  log(\"Your microphone audio is being recorded locally.\");\n});\n\nstopRecordButton.addEventListener(\"click\", () => {\n  // Stop the recording.\n  recorder.stop();\n\n  stopRecordButton.disabled = true;\n  log(\"Your microphone audio has been successfully recorded locally.\");\n});\n"}', '{}', '{"original_path": "patterns/media/microphone-record"}'), ('"picture-in-picture"', '"media"', '"vanilla"', '{"demo.css": ":root {\n  color-scheme: dark light;\n}\nhtml {\n  box-sizing: border-box;\n}\n*,\n*:before,\n*:after {\n  box-sizing: inherit;\n}\nbody {\n  margin: 1rem;\n  font-family: system-ui, sans-serif;\n}\nbutton:before {\n  content: \"Enter \";\n}\nbutton.on:before {\n  content: \"Leave \";\n}\nvideo {\n  display: block;\n  margin-top: 10px;\n  max-width: 100%;\n}\nvideo.fake-pip {\n  position: fixed;\n  z-index: 1000;\n  bottom: 10px;\n  right: 10px;\n}", "demo.html": "<!DOCTYPE html>\n<html lang=\"en\">\n  <head>\n    <meta charset=\"utf-8\" />\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />\n    <link\n      rel=\"icon\"\n      href=\"data:image/svg+xml,<svg xmlns=%22http://www.w3.org/2000/svg%22 viewBox=%220 0 100 100%22><text y=%22.9em%22 font-size=%2290%22>\ud83d\udcfa</text></svg>\"\n    />\n    <title>How to add Picture-in-Picture to video controls</title>\n  </head>\n  <body>\n    <h1>How to add Picture-in-Picture to video controls</h1>\n    <button id=\"togglePipButton\">Picture-in-Picture</button>\n    <button id=\"toggleFakePipButton\">Fake Picture-in-Picture</button>\n    <video autoplay muted playsinline loop src=\"https://storage.googleapis.com/media-session/caminandes/short.mp4\"></video>\n  </body>\n</html>\n", "demo.js": "const video = document.querySelector(''video'');\nconst togglePipButton = document.querySelector(''#togglePipButton'');\nconst toggleFakePipButton = document.querySelector(''#toggleFakePipButton'');\n\ntogglePipButton.addEventListener(\"click\", async (event) => {\n  togglePipButton.disabled = true;\n  try {\n    if (video !== document.pictureInPictureElement) {\n      await video.requestPictureInPicture();\n    } else {\n      await document.exitPictureInPicture();\n    }\n  } finally {\n    togglePipButton.disabled = false;\n  }\n});\n\nvideo.addEventListener(\"enterpictureinpicture\", (event) => {\n  togglePipButton.classList.add(\"on\");\n});\n\nvideo.addEventListener(\"leavepictureinpicture\", (event) => {\n  togglePipButton.classList.remove(\"on\");\n});\n\n/* Feature detection */\nif (\"pictureInPictureEnabled\" in document) {\n  // Hide fake PiP button if Picture-in-Picture is supported.\n  toggleFakePipButton.hidden = true;\n  // Set button ability depending on whether Picture-in-Picture can be used.\n  setPipButton();\n  video.addEventListener(\"loadedmetadata\", setPipButton);\n  video.addEventListener(\"emptied\", setPipButton);\n} else {\n  // Hide button if Picture-in-Picture is not supported.\n  togglePipButton.hidden = true;\n}\n\nfunction setPipButton() {\n  togglePipButton.disabled =\n    video.readyState === 0 ||\n    !document.pictureInPictureEnabled ||\n    video.disablePictureInPicture;\n}\n\n/* Fake Picture-in-Picture */\ntoggleFakePipButton.addEventListener(\"click\", (event) => {\n  toggleFakePipButton.classList.toggle(\"on\");\n  video.classList.toggle(\"fake-pip\");\n});"}', '{}', '{"original_path": "patterns/media/picture-in-picture"}'), ('"screen-record"', '"media"', '"vanilla"', '{"demo.css": ":root {\n  color-scheme: dark light;\n}\nhtml {\n  box-sizing: border-box;\n}\n*,\n*:before,\n*:after {\n  box-sizing: inherit;\n}\nbody {\n  margin: 1rem;\n  font-family: system-ui, sans-serif;\n}\nbutton {\n  display: block;\n  margin-bottom: 4px;\n}\nvideo {\n  display: block;\n  margin-top: 10px;\n  max-width: 100%;\n  background: black;\n  max-height: 480px;\n}\npre {\n  color: red;\n  white-space: pre-line;\n}\n", "demo.html": "<!DOCTYPE html>\n<html lang=\"en\">\n  <head>\n    <meta charset=\"utf-8\" />\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />\n    <link\n      rel=\"icon\"\n      href=\"data:image/svg+xml,<svg xmlns=%22http://www.w3.org/2000/svg%22 viewBox=%220 0 100 100%22><text y=%22.9em%22 font-size=%2290%22>\ud83d\udda5\ufe0f</text></svg>\"\n    />\n    <title>How to record the user''s screen</title>\n  </head>\n  <body>\n    <h1>How to record the user''s screen</h1>\n    <button id=\"startShareScreenButton\">Start sharing screen</button>\n    <button id=\"stopShareScreenButton\" disabled>Stop sharing screen</button>\n    <button id=\"startRecordButton\" disabled>Start recording</button>\n    <button id=\"stopRecordButton\" disabled>Stop recording</button>\n    <video autoplay muted playsinline></video>\n    <pre id=\"logs\"></pre>\n  </body>\n</html>\n", "demo.js": "const video = document.querySelector(''video'');\nconst startShareScreenButton = document.querySelector(''#startShareScreenButton'');\nconst stopShareScreenButton = document.querySelector(''#stopShareScreenButton'');\nconst startRecordButton = document.querySelector(''#startRecordButton'');\nconst stopRecordButton = document.querySelector(''#stopRecordButton'');\n\nlet stream;\nlet recorder;\n\nstartShareScreenButton.addEventListener(\"click\", async () => {\n  // Prompt the user to share their screen.\n  stream = await navigator.mediaDevices.getDisplayMedia();\n  recorder = new MediaRecorder(stream);\n  // Preview the screen locally.\n  video.srcObject = stream;\n\n  startRecordButton.disabled = false;\n  stopShareScreenButton.disabled = false;\n  log(\"Your screen is being shared.\");\n});\n\nstopShareScreenButton.addEventListener(\"click\", () => {\n  // Stop the stream.\n  stream.getTracks().forEach(track => track.stop());\n  video.srcObject = null;\n\n  stopShareScreenButton.disabled = true;\n  startRecordButton.disabled = true;\n  stopRecordButton.disabled = true;\n  log(\"Your screen is not shared anymore.\");\n});\n\nstartRecordButton.addEventListener(\"click\", async () => {\n  // For the sake of more legible code, this sample only uses the\n  // `showSaveFilePicker()` method. In production, you need to\n  // cater for browsers that don''t support this method, as\n  // outlined in https://web.dev/patterns/files/save-a-file/.\n\n  // Prompt the user to choose where to save the recording file.\n  const suggestedName = \"screen-recording.webm\";\n  const handle = await window.showSaveFilePicker({ suggestedName });\n  const writable = await handle.createWritable();\n\n  // Start recording.\n  recorder.start();\n  recorder.addEventListener(\"dataavailable\", async (event) => {\n    // Write chunks to the file.\n    await writable.write(event.data);\n    if (recorder.state === \"inactive\") {\n      // Close the file when the recording stops.\n      await writable.close();\n    }\n  });\n\n  stopRecordButton.disabled = false;\n  log(\"Your screen is being recorded locally.\");\n});\n\nstopRecordButton.addEventListener(\"click\", () => {\n  // Stop the recording.\n  recorder.stop();\n\n  stopRecordButton.disabled = true;\n  log(\"Your screen has been successfully recorded locally.\");\n});\n"}', '{}', '{"original_path": "patterns/media/screen-record"}'), ('"color-schemes"', '"theming"', '"vanilla"', '{"demo.css": "* {\n  /* brand foundation */\n  --brand-hue: 200;\n  --brand-saturation: 100%;\n  --brand-lightness: 50%;\n\n  /* light */\n  --brand-light: hsl(var(--brand-hue) var(--brand-saturation) var(--brand-lightness));\n  --text1-light: hsl(var(--brand-hue) var(--brand-saturation) 10%);\n  --text2-light: hsl(var(--brand-hue) 30% 30%);\n  --surface1-light: hsl(var(--brand-hue) 25% 90%);\n  --surface2-light: hsl(var(--brand-hue) 20% 99%);\n  --surface3-light: hsl(var(--brand-hue) 20% 92%);\n  --surface4-light: hsl(var(--brand-hue) 20% 85%);\n  --surface-shadow-light: var(--brand-hue) 10% 20%;\n  --shadow-strength-light: .02;\n\n  /* dark */\n  --brand-dark: hsl(\n    var(--brand-hue)\n    calc(var(--brand-saturation) / 2)\n    calc(var(--brand-lightness) / 1.5)\n  );\n  --text1-dark: hsl(var(--brand-hue) 15% 85%);\n  --text2-dark: hsl(var(--brand-hue) 5% 65%);\n  --surface1-dark: hsl(var(--brand-hue) 10% 10%);\n  --surface2-dark: hsl(var(--brand-hue) 10% 15%);\n  --surface3-dark: hsl(var(--brand-hue) 5%  20%);\n  --surface4-dark: hsl(var(--brand-hue) 5% 25%);\n  --surface-shadow-dark: var(--brand-hue) 50% 3%;\n  --shadow-strength-dark: .8;\n\n  /* dim */\n  --brand-dim: hsl(\n    var(--brand-hue)\n    calc(var(--brand-saturation) / 1.25)\n    calc(var(--brand-lightness) / 1.25)\n  );\n  --text1-dim: hsl(var(--brand-hue) 15% 75%);\n  --text2-dim: hsl(var(--brand-hue) 10% 61%);\n  --surface1-dim: hsl(var(--brand-hue) 10% 20%);\n  --surface2-dim: hsl(var(--brand-hue) 10% 25%);\n  --surface3-dim: hsl(var(--brand-hue) 5%  30%);\n  --surface4-dim: hsl(var(--brand-hue) 5% 35%);\n  --surface-shadow-dim: var(--brand-hue) 30% 13%;\n  --shadow-strength-dim: .2;\n}\n\n:root {\n  color-scheme: light;\n\n  /* set defaults */\n  --brand: var(--brand-light);\n  --text1: var(--text1-light);\n  --text2: var(--text2-light);\n  --surface1: var(--surface1-light);\n  --surface2: var(--surface2-light);\n  --surface3: var(--surface3-light);\n  --surface4: var(--surface4-light);\n  --surface-shadow: var(--surface-shadow-light);\n  --shadow-strength: var(--shadow-strength-light);\n}\n\n@media (prefers-color-scheme: dark) {\n  :root {\n    color-scheme: dark;\n\n    --brand: var(--brand-dark);\n    --text1: var(--text1-dark);\n    --text2: var(--text2-dark);\n    --surface1: var(--surface1-dark);\n    --surface2: var(--surface2-dark);\n    --surface3: var(--surface3-dark);\n    --surface4: var(--surface4-dark);\n    --surface-shadow: var(--surface-shadow-dark);\n    --shadow-strength: var(--shadow-strength-dark);\n  }\n}\n\n[color-scheme=\"light\"] {\n  color-scheme: light;\n\n  --brand: var(--brand-light);\n  --text1: var(--text1-light);\n  --text2: var(--text2-light);\n  --surface1: var(--surface1-light);\n  --surface2: var(--surface2-light);\n  --surface3: var(--surface3-light);\n  --surface4: var(--surface4-light);\n  --surface-shadow: var(--surface-shadow-light);\n  --shadow-strength: var(--shadow-strength-light);\n}\n\n[color-scheme=\"dark\"] {\n  color-scheme: dark;\n\n  --brand: var(--brand-dark);\n  --text1: var(--text1-dark);\n  --text2: var(--text2-dark);\n  --surface1: var(--surface1-dark);\n  --surface2: var(--surface2-dark);\n  --surface3: var(--surface3-dark);\n  --surface4: var(--surface4-dark);\n  --surface-shadow: var(--surface-shadow-dark);\n  --shadow-strength: var(--shadow-strength-dark);\n}\n\n[color-scheme=\"dim\"] {\n  color-scheme: dark;\n\n  --brand: var(--brand-dim);\n  --text1: var(--text1-dim);\n  --text2: var(--text2-dim);\n  --surface1: var(--surface1-dim);\n  --surface2: var(--surface2-dim);\n  --surface3: var(--surface3-dim);\n  --surface4: var(--surface4-dim);\n  --surface-shadow: var(--surface-shadow-dim);\n  --shadow-strength: var(--shadow-strength-dim);\n}\n\n/* READY TO USE! */\n.brand {\n  color: var(--brand);\n  background-color: var(--brand);\n}\n\n.surface1 {\n  background-color: var(--surface1);\n  color: var(--text2);\n}\n\n.surface2 {\n  background-color: var(--surface2);\n  color: var(--text2);\n}\n\n.surface3 {\n  background-color: var(--surface3);\n  color: var(--text1);\n}\n\n.surface4 {\n  background-color: var(--surface4);\n  color: var(--text1);\n}\n\n.text1 {\n  color: var(--text1);\n}\n\np.text1 {\n  font-weight: 200;\n}\n\n.text2 {\n  color: var(--text2);\n}\n", "demo.html": "<header>\n  <h3>Scheme</h3>\n  <form id=\"theme-switcher\">\n    <div>\n      <input checked type=\"radio\" id=\"auto\" name=\"theme\" value=\"auto\">\n      <label for=\"auto\">Auto</label>\n    </div>\n    <div>\n      <input type=\"radio\" id=\"light\" name=\"theme\" value=\"light\">\n      <label for=\"light\">Light</label>\n    </div>\n    <div>\n      <input type=\"radio\" id=\"dark\" name=\"theme\" value=\"dark\">\n      <label for=\"dark\">Dark</label>\n    </div>\n    <div>\n      <input type=\"radio\" id=\"dim\" name=\"theme\" value=\"dim\">\n      <label for=\"dim\">Dim</label>\n    </div>\n  </form>\n</header>\n\n<main>\n  <section>\n    <div class=\"surface-samples\">\n      <div class=\"surface1 rad-shadow\">1</div>\n      <div class=\"surface2 rad-shadow\">2</div>\n      <div class=\"surface3 rad-shadow\">3</div>\n      <div class=\"surface4 rad-shadow\">4</div>\n    </div>\n  </section>\n\n  <section>\n    <div class=\"text-samples\">\n      <h1 class=\"text1\">\n        <span class=\"swatch brand rad-shadow\"></span>\n        Brand\n      </h1>\n      <h1 class=\"text1\">\n        <span class=\"swatch text1 rad-shadow\"></span>\n        Text Color 1\n      </h1>\n      <h1 class=\"text2\">\n        <span class=\"swatch text2 rad-shadow\"></span>\n        Text Color 2\n      </h1>\n      <br>\n      <p class=\"text1\">Lorem ipsum dolor sit amet, consectetur adipiscing elit, sed do eiusmod tempor incididunt ut labore et dolore magna aliqua.</p>\n      <p class=\"text2\">Ut enim ad minim veniam, quis nostrud exercitation ullamco laboris nisi ut aliquip ex ea commodo consequat.</p>\n    </div>\n  </section>\n</main>", "demo.js": "const switcher = document.querySelector(''#theme-switcher'')\nconst doc = document.firstElementChild\n\nswitcher.addEventListener(''input'', e =>\n  setTheme(e.target.value))\n\nconst setTheme = theme =>\n  doc.setAttribute(''color-scheme'', theme)"}', '{}', '{"original_path": "patterns/theming/color-schemes"}'), ('"hsl-starter-kit"', '"theming"', '"vanilla"', '{"demo.css": ":root {\n  color-scheme: dark light;\n\n  /* destructure brand channels */\n  --hue: 200; /* change me!! */\n  --saturation: 100%;\n  --lightness: 50%;\n\n  /* build colors with props */\n  --brand: hsl(\n    var(--hue)\n    var(--saturation)\n    var(--lightness)\n  );\n\n  /* very dark brand blue */\n  --text: hsl(\n    var(--hue)\n    var(--saturation)\n    10% /* lower is darker */\n  );\n\n  /* very bright brand white */\n  --surface: hsl(\n    var(--hue)\n    calc(var(--saturation) / 2)\n    95% /* higher is lighter */\n  );\n}\n\nh1 {\n  font-size: 10vmin;\n  font-weight: 300;\n}\n\nb {\n  color: hsl(\n    var(--hue)\n    var(--saturation)\n    30%\n  );\n}\n\nu {\n  text-decoration-color: var(--brand);\n}\n\nhtml {\n  block-size: 100%;\n  inline-size: 100%;\n}\n\nbody {\n  color: var(--text);\n  background: var(--surface);\n  min-block-size: 100%;\n  min-inline-size: 100%;\n  margin: 0;\n  box-sizing: border-box;\n  display: grid;\n  place-content: center;\n  font-family: system-ui, sans-serif;\n}\n\n@media (prefers-color-scheme: dark) {\n  /* just tweak the lightness */\n  /* maybe desaturate too */\n\n  :root {\n    --text: hsl(\n      var(--hue)\n      calc(var(--saturation) / 2)\n      85%\n    );\n\n    --surface: hsl(\n      var(--hue)\n      var(--saturation)\n      5%\n    );\n  }\n\n  b {\n    color: hsl(\n      var(--hue)\n      var(--saturation)\n      75%\n    );\n  }\n}\n", "demo.html": "<h1><b>HSL</b> is <u>awesome.</u></h1>\n"}', '{}', '{"original_path": "patterns/theming/hsl-starter-kit"}');